import xml.etree.ElementTree as ET
from datetime import datetime, timezone
import logging

from .exceptions import SAMLValidationError

logger = logging.getLogger(__name__)

SAML_NAMESPACES = {
    'samlp': 'urn:oasis:names:tc:SAML:2.0:protocol',
    'saml': 'urn:oasis:names:tc:SAML:2.0:assertion',
    'ds': 'http://www.w3.org/2000/09/xmldsig#',
    'xenc': 'http://www.w3.org/2001/04/xmlenc#',
}


class SAMLXMLValidator:
    """Validates SAML XML structure and basic constraints."""

    def __init__(self, xml_string):
        self.xml_string = xml_string
        self.root = None
        self.errors = []

    def parse(self):
        """Parse XML string into ElementTree."""
        try:
            if isinstance(self.xml_string, bytes):
                xml_data = self.xml_string
            else:
                xml_data = self.xml_string.encode('utf-8')

            # Basic security checks before parsing
            self._check_xml_attacks(xml_data)

            self.root = ET.fromstring(xml_data)
            return self.root
        except ET.ParseError as e:
            raise SAMLValidationError(f"Invalid XML: {e}")

    def _check_xml_attacks(self, xml_data):
        """Check for common XML attack patterns."""
        xml_str = xml_data.decode('utf-8', errors='replace').lower()

        # Check for XML External Entity (XXE) attacks
        if '<!entity' in xml_str or '<!doctype' in xml_str:
            raise SAMLValidationError(
                "XML contains DOCTYPE or ENTITY declarations, which are not allowed in SAML"
            )

        # Check for XML bomb / billion laughs
        if xml_str.count('<!') > 0:
            raise SAMLValidationError(
                "XML contains markup declarations, which are not allowed in SAML"
            )

        # Check for extremely large XML
        if len(xml_data) > 500000:  # 500KB limit
            raise SAMLValidationError("SAML response exceeds maximum allowed size")

    def validate_structure(self):
        """Validate the overall SAML response structure."""
        if self.root is None:
            self.parse()

        self._validate_root_element()
        self._validate_status()
        self._validate_assertion_exists()
        self._validate_conditions()

        if self.errors:
            raise SAMLValidationError(
                f"SAML validation failed: {'; '.join(self.errors)}"
            )

        return True

    def _validate_root_element(self):
        """Validate the root element is a SAML Response."""
        expected_tag = f"{{{SAML_NAMESPACES['samlp']}}}Response"
        if self.root.tag != expected_tag:
            self.errors.append(
                f"Root element must be samlp:Response, got {self.root.tag}"
            )

        # Check required attributes
        if 'ID' not in self.root.attrib:
            self.errors.append("Response missing required 'ID' attribute")

        if 'Version' not in self.root.attrib:
            self.errors.append("Response missing required 'Version' attribute")
        elif self.root.attrib['Version'] != '2.0':
            self.errors.append(
                f"Unsupported SAML version: {self.root.attrib['Version']}"
            )

        if 'IssueInstant' not in self.root.attrib:
            self.errors.append("Response missing required 'IssueInstant' attribute")

    def _validate_status(self):
        """Validate the SAML response status."""
        status = self.root.find('samlp:Status', SAML_NAMESPACES)
        if status is None:
            self.errors.append("Response missing Status element")
            return

        status_code = status.find('samlp:StatusCode', SAML_NAMESPACES)
        if status_code is None:
            self.errors.append("Status missing StatusCode element")
            return

        status_value = status_code.get('Value', '')
        success_status = 'urn:oasis:names:tc:SAML:2.0:status:Success'

        if status_value != success_status:
            status_message = status.find('samlp:StatusMessage', SAML_NAMESPACES)
            msg = status_message.text if status_message is not None else 'Unknown error'
            self.errors.append(
                f"SAML authentication failed. Status: {status_value}, Message: {msg}"
            )

    def _validate_assertion_exists(self):
        """Validate that at least one assertion exists."""
        assertion = self.root.find('saml:Assertion', SAML_NAMESPACES)
        if assertion is None:
            self.errors.append("Response missing Assertion element")
            return

        # Validate assertion has required elements
        issuer = assertion.find('saml:Issuer', SAML_NAMESPACES)
        if issuer is None:
            self.errors.append("Assertion missing Issuer element")

        subject = assertion.find('saml:Subject', SAML_NAMESPACES)
        if subject is None:
            self.errors.append("Assertion missing Subject element")
        else:
            name_id = subject.find('saml:NameID', SAML_NAMESPACES)
            if name_id is None:
                self.errors.append("Subject missing NameID element")

        authn_statement = assertion.find('saml:AuthnStatement', SAML_NAMESPACES)
        if authn_statement is None:
            self.errors.append("Assertion missing AuthnStatement element")

    def _validate_conditions(self):
        """Validate assertion conditions (time-based)."""
        assertion = self.root.find('saml:Assertion', SAML_NAMESPACES)
        if assertion is None:
            return

        conditions = assertion.find('saml:Conditions', SAML_NAMESPACES)
        if conditions is None:
            logger.warning("Assertion has no Conditions element")
            return

        now = datetime.now(timezone.utc)

        not_before = conditions.get('NotBefore')
        if not_before:
            try:
                not_before_dt = self._parse_saml_datetime(not_before)
                # Allow 5 minutes clock skew
                from datetime import timedelta
                if now < not_before_dt - timedelta(minutes=5):
                    self.errors.append(
                        f"Assertion not yet valid. NotBefore: {not_before}"
                    )
            except ValueError as e:
                self.errors.append(f"Invalid NotBefore datetime: {e}")

        not_on_or_after = conditions.get('NotOnOrAfter')
        if not_on_or_after:
            try:
                not_on_or_after_dt = self._parse_saml_datetime(not_on_or_after)
                from datetime import timedelta
                if now >= not_on_or_after_dt + timedelta(minutes=5):
                    self.errors.append(
                        f"Assertion has expired. NotOnOrAfter: {not_on_or_after}"
                    )
            except ValueError as e:
                self.errors.append(f"Invalid NotOnOrAfter datetime: {e}")

    @staticmethod
    def _parse_saml_datetime(dt_string):
        """Parse a SAML datetime string."""
        formats = [
            '%Y-%m-%dT%H:%M:%SZ',
            '%Y-%m-%dT%H:%M:%S.%fZ',
            '%Y-%m-%dT%H:%M:%S%z',
        ]
        for fmt in formats:
            try:
                dt = datetime.strptime(dt_string, fmt)
                if dt.tzinfo is None:
                    dt = dt.replace(tzinfo=timezone.utc)
                return dt
            except ValueError:
                continue
        raise ValueError(f"Unable to parse datetime: {dt_string}")


