import xml.etree.ElementTree as ET
import logging

from .xml_validator import SAML_NAMESPACES
from .exceptions import SAMLResponseError

logger = logging.getLogger(__name__)


class SAMLResponseParser:
    """Parses SAML Response XML and extracts user information."""

    def __init__(self, root_element, attribute_mapping=None):
        self.root = root_element
        self.attribute_mapping = attribute_mapping or {}
        self._assertion = None
        self._name_id = None
        self._name_id_format = None
        self._session_index = None
        self._attributes = {}
        self._issuer = None
        self._parsed = False

    def parse(self):
        """Parse the SAML response and extract all relevant data."""
        self._extract_issuer()
        self._extract_assertion()
        self._extract_name_id()
        self._extract_session_index()
        self._extract_attributes()
        self._parsed = True
        return self

    def _extract_issuer(self):
        """Extract the response-level Issuer."""
        issuer = self.root.find('saml:Issuer', SAML_NAMESPACES)
        if issuer is not None:
            self._issuer = issuer.text

    def _extract_assertion(self):
        """Extract the first assertion from the response."""
        self._assertion = self.root.find('saml:Assertion', SAML_NAMESPACES)
        if self._assertion is None:
            raise SAMLResponseError("No assertion found in SAML response")

    def _extract_name_id(self):
        """Extract NameID from the assertion subject."""
        if self._assertion is None:
            raise SAMLResponseError("No assertion available")

        subject = self._assertion.find('saml:Subject', SAML_NAMESPACES)
        if subject is None:
            raise SAMLResponseError("No Subject found in assertion")

        name_id_elem = subject.find('saml:NameID', SAML_NAMESPACES)
        if name_id_elem is None:
            raise SAMLResponseError("No NameID found in Subject")

        self._name_id = name_id_elem.text
        self._name_id_format = name_id_elem.get('Format', '')

        if not self._name_id:
            raise SAMLResponseError("NameID value is empty")

    def _extract_session_index(self):
        """Extract session index from AuthnStatement."""
        if self._assertion is None:
            return

        authn_statement = self._assertion.find(
            'saml:AuthnStatement', SAML_NAMESPACES
        )
        if authn_statement is not None:
            self._session_index = authn_statement.get('SessionIndex')

    def _extract_attributes(self):
        """Extract attributes from the assertion's AttributeStatement."""
        if self._assertion is None:
            return

        attr_statement = self._assertion.find(
            'saml:AttributeStatement', SAML_NAMESPACES
        )
        if attr_statement is None:
            logger.warning("No AttributeStatement found in assertion")
            return

        for attribute in attr_statement.findall('saml:Attribute', SAML_NAMESPACES):
            attr_name = attribute.get('Name', '')
            attr_friendly_name = attribute.get('FriendlyName', '')

            values = []
            for attr_value in attribute.findall(
                'saml:AttributeValue', SAML_NAMESPACES
            ):
                if attr_value.text:
                    values.append(attr_value.text.strip())

            # Store by both Name and FriendlyName
            if attr_name:
                self._attributes[attr_name] = values
            if attr_friendly_name:
                self._attributes[attr_friendly_name] = values

        logger.debug(f"Extracted SAML attributes: {list(self._attributes.keys())}")

    @property
    def name_id(self):
        if not self._parsed:
            self.parse()
        return self._name_id

    @property
    def name_id_format(self):
        if not self._parsed:
            self.parse()
        return self._name_id_format

    @property
    def session_index(self):
        if not self._parsed:
            self.parse()
        return self._session_index

    @property
    def issuer(self):
        if not self._parsed:
            self.parse()
        return self._issuer

    @property
    def attributes(self):
        if not self._parsed:
            self.parse()
        return self._attributes

    def get_mapped_attributes(self):
        """Map SAML attributes to Django user fields using the attribute mapping."""
        if not self._parsed:
            self.parse()

        mapped = {}
        for saml_attr, django_field in self.attribute_mapping.items():
            if saml_attr in self._attributes:
                values = self._attributes[saml_attr]
                # Use first value for single-valued fields
                mapped[django_field] = values[0] if values else ''

        return mapped

    def get_user_identity(self):
        """Get a complete user identity dict."""
        if not self._parsed:
            self.parse()

        mapped_attrs = self.get_mapped_attributes()

        return {
            'name_id': self._name_id,
            'name_id_format': self._name_id_format,
            'session_index': self._session_index,
            'issuer': self._issuer,
            'attributes': self._attributes,
            'mapped_attributes': mapped_attrs,
        }


