from django.db import models
from django.conf import settings


class SAMLSession(models.Model):
    """Stores SAML session information for single logout support."""
    user = models.ForeignKey(
        settings.AUTH_USER_MODEL,
        on_delete=models.CASCADE,
        related_name='saml_sessions',
    )
    name_id = models.CharField(max_length=512)
    name_id_format = models.CharField(max_length=256, blank=True, default='')
    session_index = models.CharField(max_length=256, blank=True, null=True)
    django_session_key = models.CharField(max_length=40)
    issuer = models.CharField(max_length=512, blank=True, default='')
    created_at = models.DateTimeField(auto_now_add=True)

    class Meta:
        indexes = [
            models.Index(fields=['name_id']),
            models.Index(fields=['session_index']),
            models.Index(fields=['django_session_key']),
        ]

    def __str__(self):
        return f"SAMLSession for {self.user} (NameID: {self.name_id})"


class SAMLResponseLog(models.Model):
    """Logs SAML responses for debugging and audit purposes."""
    response_id = models.CharField(max_length=256, unique=True)
    issuer = models.CharField(max_length=512, blank=True, default='')
    name_id = models.CharField(max_length=512, blank=True, default='')
    status = models.CharField(max_length=50)
    user = models.ForeignKey(
        settings.AUTH_USER_MODEL,
        on_delete=models.SET_NULL,
        null=True,
        blank=True,
    )
    ip_address = models.GenericIPAddressField(null=True, blank=True)
    created_at = models.DateTimeField(auto_now_add=True)
    error_message = models.TextField(blank=True, default='')

    class Meta:
        ordering = ['-created_at']

    def __str__(self):
        return f"SAMLResponse {self.response_id} - {self.status}"


