import logging
from django.contrib.auth import get_user_model
from django.conf import settings

logger = logging.getLogger(__name__)
User = get_user_model()


class SAMLAuthenticationBackend:
    """Django authentication backend for SAML SSO."""

    def authenticate(self, request=None, saml_user_identity=None, **kwargs):
        """Authenticate a user based on SAML assertion data."""
        if saml_user_identity is None:
            return None

        saml_settings = getattr(settings, 'SAML_SP_SETTINGS', {})
        create_unknown = saml_settings.get('create_unknown_user', True)
        update_on_login = saml_settings.get('update_user_on_login', True)

        name_id = saml_user_identity.get('name_id')
        mapped_attrs = saml_user_identity.get('mapped_attributes', {})

        if not name_id:
            logger.error("No NameID in SAML user identity")
            return None

        # Determine the username
        username = mapped_attrs.get('username', name_id)
        email = mapped_attrs.get('email', '')

        # Try to find existing user
        user = self._find_user(username, email, name_id)

        if user is None and create_unknown:
            user = self._create_user(username, email, mapped_attrs)
            logger.info(f"Created new user from SAML: {username}")
        elif user is not None and update_on_login:
            user = self._update_user(user, mapped_attrs)
            logger.info(f"Updated user from SAML: {username}")

        return user

    def _find_user(self, username, email, name_id):
        """Find an existing user by username or email."""
        # Try by username first
        try:
            return User.objects.get(username=username)
        except User.DoesNotExist:
            pass

        # Try by email
        if email:
            try:
                return User.objects.get(email=email)
            except User.DoesNotExist:
                pass
            except User.MultipleObjectsReturned:
                logger.warning(f"Multiple users found with email: {email}")
                return User.objects.filter(email=email).first()

        return None

    def _create_user(self, username, email, mapped_attrs):
        """Create a new Django user from SAML attributes."""
        user_data = {
            'username': username[:150],  # Django username max length
            'email': email[:254] if email else '',
            'first_name': mapped_attrs.get('first_name', '')[:150],
            'last_name': mapped_attrs.get('last_name', '')[:150],
        }

        user = User(**user_data)
        user.set_unusable_password()
        user.save()

        return user

    def _update_user(self, user, mapped_attrs):
        """Update existing user with SAML attributes."""
        updated = False

        if 'email' in mapped_attrs and mapped_attrs['email']:
            new_email = mapped_attrs['email'][:254]
            if user.email != new_email:
                user.email = new_email
                updated = True

        if 'first_name' in mapped_attrs and mapped_attrs['first_name']:
            new_first = mapped_attrs['first_name'][:150]
            if user.first_name != new_first:
                user.first_name = new_first
                updated = True

        if 'last_name' in mapped_attrs and mapped_attrs['last_name']:
            new_last = mapped_attrs['last_name'][:150]
            if user.last_name != new_last:
                user.last_name = new_last
                updated = True

        if updated:
            user.save()

        return user

    def get_user(self, user_id):
        """Required by Django auth backend interface."""
        try:
            return User.objects.get(pk=user_id)
        except User.DoesNotExist:
            return None


# saml_sp/session_manager.py
import logging
from django.contrib.auth import login as auth_login
from django.contrib.auth import authenticate

from .models import SAMLSession, SAMLResponseLog

logger = logging.getLogger(__name__)


class SAMLSessionManager:
    """Manages Django sessions based on SAML authentication."""

    def __init__(self, request):
        self.request = request

    def create_session(self, user_identity):
        """Create a Django session from SAML user identity."""
        # Authenticate user through Django's auth system
        user = authenticate(
            request=self.request,
            saml_user_identity=user_identity,
        )

        if user is None:
            logger.error(
                f"Failed to authenticate SAML user: {user_identity.get('name_id')}"
            )
            return None

        if not user.is_active:
            logger.warning(f"SAML user is inactive: {user.username}")
            return None

        # Log in the user (creates Django session)
        auth_login(self.request, user, backend='saml_sp.auth_backend.SAMLAuthenticationBackend')

        # Store SAML session data
        saml_session = SAMLSession.objects.create(
            user=user,
            name_id=user_identity.get('name_id', ''),
            name_id_format=user_identity.get('name_id_format', ''),
            session_index=user_identity.get('session_index'),
            django_session_key=self.request.session.session_key or '',
            issuer=user_identity.get('issuer', ''),
        )

        # Store SAML data in Django session
        self.request.session['saml_name_id'] = user_identity.get('name_id')
        self.request.session['saml_session_index'] = user_identity.get('session_index')
        self.request.session['saml_issuer'] = user_identity.get('issuer')
        self.request.session['saml_attributes'] = user_identity.get('attributes', {})

        logger.info(
            f"Created SAML session for user {user.username} "
            f"(NameID: {user_identity.get('name_id')})"
        )

        return user

    def log_response(self, response_id, issuer, name_id, status, user=None,
                     error_message=''):
        """Log a SAML response for audit purposes."""
        ip_address = self._get_client_ip()

        try:
            SAMLResponseLog.objects.create(
                response_id=response_id,
                issuer=issuer or '',
                name_id=name_id or '',
                status=status,
                user=user,
                ip_address=ip_address,
                error_message=error_message,
            )
        except Exception as e:
            logger.error(f"Failed to log SAML response: {e}")

    def _get_client_ip(self):
        """Get client IP address from request."""
        x_forwarded_for = self.request.META.get('HTTP_X_FORWARDED_FOR')
        if x_forwarded_for:
            return x_forwarded_for.split(',')[0].strip()
        return self.request.META.get('REMOTE_ADDR')


