import base64
import zlib
import logging
import uuid
from datetime import datetime, timezone
from urllib.parse import urlencode

from django.conf import settings
from django.http import HttpResponseRedirect, HttpResponseBadRequest, HttpResponse
from django.views import View
from django.views.decorators.csrf import csrf_exempt
from django.utils.decorators import method_decorator
from django.contrib.auth import logout as auth_logout

from .xml_validator import SAMLXMLValidator
from .parser import SAMLResponseParser
from .session_manager import SAMLSessionManager
from .exceptions import SAMLError, SAMLValidationError, SAMLResponseError

logger = logging.getLogger(__name__)


def get_saml_settings():
    """Get SAML SP settings from Django settings."""
    return getattr(settings, 'SAML_SP_SETTINGS', {})


class SAMLLoginView(View):
    """Initiates SAML authentication by redirecting to IdP."""

    def get(self, request):
        saml_settings = get_saml_settings()

        idp_sso_url = saml_settings.get('idp_sso_url')
        if not idp_sso_url:
            return HttpResponseBadRequest("SAML IdP SSO URL not configured")

        # Store RelayState (where to redirect after login)
        relay_state = request.GET.get('next', '/')
        request.session['saml_relay_state'] = relay_state

        # Build AuthnRequest
        authn_request = self._build_authn_request(saml_settings)

        # Encode the request
        encoded_request = self._encode_request(authn_request)

        # Build redirect URL
        params = {
            'SAMLRequest': encoded_request,
            'RelayState': relay_state,
        }

        redirect_url = f"{idp_sso_url}?{urlencode(params)}"
        return HttpResponseRedirect(redirect_url)

    def _build_authn_request(self, saml_settings):
        """Build a SAML AuthnRequest XML."""
        request_id = f"_{''.join(str(uuid.uuid4()).split('-'))}"
        issue_instant = datetime.now(timezone.utc).strftime('%Y-%m-%dT%H:%M:%SZ')
        entity_id = saml_settings.get('entity_id', '')
        acs_url = saml_settings.get('acs_url', '')
        idp_entity_id = saml_settings.get('idp_entity_id', '')

        authn_request = f"""<?xml version="1.0" encoding="UTF-8"?>
<samlp:AuthnRequest
    xmlns:samlp="urn:oasis:names:tc:SAML:2.0:protocol"
    xmlns:saml="urn:oasis:names:tc:SAML:2.0:assertion"
    ID="{request_id}"
    Version="2.0"
    IssueInstant="{issue_instant}"
    Destination="{saml_settings.get('idp_sso_url', '')}"
    ProtocolBinding="urn:oasis:names:tc:SAML:2.0:bindings:HTTP-POST"
    AssertionConsumerServiceURL="{acs_url}">
    <saml:Issuer>{entity_id}</saml:Issuer>
    <samlp:NameIDPolicy
        Format="urn:oasis:names:tc:SAML:1.1:nameid-format:emailAddress"
        AllowCreate="true"/>
</samlp:AuthnRequest>"""

        return authn_request

    def _encode_request(self, authn_request):
        """Deflate and base64 encode the AuthnRequest for HTTP-Redirect binding."""
        compressed = zlib.compress(authn_request.encode('utf-8'))[2:-4]
        encoded = base64.b64encode(compressed).decode('utf-8')
        return encoded


@method_decorator(csrf_exempt, name='dispatch')
class SAMLACSView(View):
    """Assertion Consumer Service - handles SAML POST responses from IdP."""

    def post(self, request):
        """Handle SAML Response via HTTP POST binding."""
        saml_response_b64 = request.POST.get('SAMLResponse')
        relay_state = request.POST.get('RelayState', '/')

        if not saml_response_b64:
            logger.error("No SAMLResponse in POST data")
            return HttpResponseBadRequest("Missing SAMLResponse")

        session_manager = SAMLSessionManager(request)

        try:
            # Decode the SAML response
            xml_string = self._decode_response(saml_response_b64)

            # Validate XML structure
            validator = SAMLXMLValidator(xml_string)
            validator.parse()
            validator.validate_structure()

            # Parse user information
            saml_settings = get_saml_settings()
            attribute_mapping = saml_settings.get('attribute_mapping', {})

            parser = SAMLResponseParser(validator.root, attribute_mapping)
            parser.parse()

            user_identity = parser.get_user_identity()

            # Create Django session
            user = session_manager.create_session(user_identity)

            if user is None:
                # Log failure
                response_id = validator.root.get('ID', 'unknown')
                session_manager.log_response(
                    response_id=response_id,
                    issuer=parser.issuer,
                    name_id=parser.name_id,
                    status='auth_failed',
                    error_message='Failed to authenticate or create user',
                )
                return HttpResponseBadRequest(
                    "Authentication failed. Unable to create user session."
                )

            # Log success
            response_id = validator.root.get('ID', 'unknown')
            session_manager.log_response(
                response_id=response_id,
                issuer=parser.issuer,
                name_id=parser.name_id,
                status='success',
                user=user,
            )

            logger.info(f"SAML SSO login successful for user: {user.username}")

            # Redirect to RelayState or default
            redirect_url = relay_state or request.session.get('saml_relay_state', '/')
            return HttpResponseRedirect(redirect_url)

        except SAMLValidationError as e:
            logger.error(f"SAML validation error: {e}")
            session_manager.log_response(
                response_id='unknown',
                issuer='',
                name_id='',
                status='validation_error',
                error_message=str(e),
            )
            return HttpResponseBadRequest(f"SAML Validation Error: {e}")

        except SAMLResponseError as e:
            logger.error(f"SAML response error: {e}")
            session_manager.log_response(
                response_id='unknown',
                issuer='',
                name_id='',
                status='parse_error',
                error_message=str(e),
            )
            return HttpResponseBadRequest(f"SAML Response Error: {e}")

        except SAMLError as e:
            logger.error(f"SAML error: {e}")
            return HttpResponseBadRequest(f"SAML Error: {e}")

        except Exception as e:
            logger.exception(f"Unexpected error processing SAML response: {e}")
            return HttpResponseBadRequest("An unexpected error occurred during SAML authentication.")

    def _decode_response(self, saml_response_b64):
        """Decode base64 SAML response."""
        try:
            xml_bytes = base64.b64decode(saml_response_b64)
            return xml_bytes
        except Exception as e:
            raise SAMLValidationError(f"Failed to decode SAML response: {e}")


class SAMLLogoutView(View):
    """Handle logout - clears SAML session."""

    def get(self, request):
        return self._logout(request)

    def post(self, request):
        return self._logout(request)

    def _logout(self, request):
        """Perform logout."""
        if request.user.is_authenticated:
            # Clean up SAML session records
            session_key = request.session.session_key
            if session_key:
                from .models import SAMLSession
                SAMLSession.objects.filter(
                    django_session_key=session_key
                ).delete()

            logger.info(f"SAML logout for user: {request.user.username}")

        auth_logout(request)

        saml_settings = get_saml_settings()
        logout_redirect = saml_settings.get('logout_redirect', '/')

        return HttpResponseRedirect(logout_redirect)


class SAMLMetadataView(View):
    """Serve SP metadata XML."""

    def get(self, request):
        saml_settings = get_saml_settings()

        entity_id = saml_settings.get('entity_id', '')
        acs_url = saml_settings.get('acs_url', '')

        metadata = f"""<?xml version="1.0" encoding="UTF-8"?>
<md:EntityDescriptor
    xmlns:md="urn:oasis:names:tc:SAML:2.0:metadata"
    entityID="{entity_id}">
    <md:SPSSODescriptor
        AuthnRequestsSigned="false"
        WantAssertionsSigned="true"
        protocolSupportEnumeration="urn:oasis:names:tc:SAML:2.0:protocol">
        <md:NameIDFormat>urn:oasis:names:tc:SAML:1.1:nameid-format:emailAddress</md:NameIDFormat>
        <md:NameIDFormat>urn:oasis:names:tc:SAML:2.0:nameid-format:persistent</md:NameIDFormat>
        <md:NameIDFormat>urn:oasis:names:tc:SAML:2.0:nameid-format:transient</md:NameIDFormat>
        <md:AssertionConsumerService
            Binding="urn:oasis:names:tc:SAML:2.0:bindings:HTTP-POST"
            Location="{acs_url}"
            index="1"
            isDefault="true"/>
    </md:SPSSODescriptor>
</md:EntityDescriptor>"""

        return HttpResponse(metadata, content_type='application/xml')


