# saml_sp/middleware.py
import logging
from django.conf import settings
from django.shortcuts import redirect
from django.urls import reverse

logger = logging.getLogger(__name__)


class SAMLAuthMiddleware:
    """Middleware to enforce SAML authentication on protected views."""

    def __init__(self, get_response):
        self.get_response = get_response
        self.exempt_urls = getattr(settings, 'SAML_EXEMPT_URLS', [])

    def __call__(self, request):
        # Add default exempt URLs
        exempt_paths = [
            '/saml/login/',
            '/saml/acs/',
            '/saml/metadata/',
            '/saml/logout/',
            '/admin/',
        ]
        exempt_paths.extend(self.exempt_urls)

        # Check if the request path is exempt
        is_exempt = any(request.path.startswith(path) for path in exempt_paths)

        if not is_exempt and not request.user.is_authenticated:
            saml_settings = getattr(settings, 'SAML_SP_SETTINGS', {})
            if saml_settings.get('enforce_saml_login', False):
                login_url = reverse('saml_sp:saml_login')
                return redirect(f"{login_url}?next={request.path}")

        response = self.get_response(request)
        return response


