User = get_user_model()

SAML_TEST_SETTINGS = {
    'entity_id': 'https://test.example.com/saml/metadata/',
    'acs_url': 'https://test.example.com/saml/acs/',
    'idp_entity_id': 'https://idp.example.com/',
    'idp_sso_url': 'https://idp.example.com/sso/',
    'attribute_mapping': {
        'http://schemas.xmlsoap.org/ws/2005/05/identity/claims/emailaddress': 'email',
        'http://schemas.xmlsoap.org/ws/2005/05/identity/claims/givenname': 'first_name',
        'http://schemas.xmlsoap.org/ws/2005/05/identity/claims/surname': 'last_name',
        'http://schemas.xmlsoap.org/ws/2005/05/identity/claims/name': 'username',
    },
    'create_unknown_user': True,
    'update_user_on_login': True,
}


def build_saml_response(name_id='user@example.com', issuer='https://idp.example.com/',
                         first_name='John', last_name='Doe',
                         email='user@example.com', status_success=True,
                         not_before=None, not_on_or_after=None):
    """Build a test SAML response XML."""
    now = datetime.now(timezone.utc)
    if not_before is None:
        not_before = (now - timedelta(minutes=5)).strftime('%Y-%m-%dT%H:%M:%SZ')
    if not_on_or_after is None:
        not_on_or_after = (now + timedelta(hours=1)).strftime('%Y-%m-%dT%H:%M:%SZ')

    issue_instant = now.strftime('%Y-%m-%dT%H:%M:%SZ')

    status_value = (
        'urn:oasis:names:tc:SAML:2.0:status:Success' if status_success
        else 'urn:oasis:names:tc:SAML:2.0:status:Responder'
    )

    xml = f"""<?xml version="1.0" encoding="UTF-8"?>
<samlp:Response
    xmlns:samlp="urn:oasis:names:tc:SAML:2.0:protocol"
    xmlns:saml="urn:oasis:names:tc:SAML:2.0:assertion"
    ID="_response_123"
    Version="2.0"
    IssueInstant="{issue_instant}"
    Destination="https://test.example.com/saml/acs/">
    <saml:Issuer>{issuer}</saml:Issuer>
    <samlp:Status>
        <samlp:StatusCode Value="{status_value}"/>
    </samlp:Status>
    <saml:Assertion
        ID="_assertion_456"
        Version="2.0"
        IssueInstant="{issue_instant}">
        <saml:Issuer>{issuer}</saml:Issuer>
        <saml:Subject>
            <saml:NameID Format="urn:oasis:names:tc:SAML:1.1:nameid-format:emailAddress">{name_id}</saml:NameID>
            <saml:SubjectConfirmation Method="urn:oasis:names:tc:SAML:2.0:cm:bearer">
                <saml:SubjectConfirmationData
                    NotOnOrAfter="{not_on_or_after}"
                    Recipient="https://test.example.com/saml/acs/"/>
            </saml:SubjectConfirmation>
        </saml:Subject>
        <saml:Conditions NotBefore="{not_before}" NotOnOrAfter="{not_on_or_after}">
            <saml:AudienceRestriction>
                <saml:Audience>https://test.example.com/saml/metadata/</saml:Audience>
            </saml:AudienceRestriction>
        </saml:Conditions>
        <saml:AuthnStatement AuthnInstant="{issue_instant}" SessionIndex="_session_789">
            <saml:AuthnContext>
                <saml:AuthnContextClassRef>urn:oasis:names:tc:SAML:2.0:ac:classes:PasswordProtectedTransport</saml:AuthnContextClassRef>
            </saml:AuthnContext>
        </saml:AuthnStatement>
        <saml:AttributeStatement>
            <saml:Attribute Name="http://schemas.xmlsoap.org/ws/2005/05/identity/claims/emailaddress">
                <saml:AttributeValue>{email}</saml:AttributeValue>
            </saml:Attribute>
            <saml:Attribute Name="http://schemas.xmlsoap.org/ws/2005/05/identity/claims/givenname">
                <saml:AttributeValue>{first_name}</saml:AttributeValue>
            </saml:Attribute>
            <saml:Attribute Name="http://schemas.xmlsoap.org/ws/2005/05/identity/claims/surname">
                <saml:AttributeValue>{last_name}</saml:AttributeValue>
            </saml:Attribute>
            <saml:Attribute Name="http://schemas.xmlsoap.org/ws/2005/05/identity/claims/name">
                <saml:AttributeValue>{name_id}</saml:AttributeValue>
            </saml:Attribute>
        </saml:AttributeStatement>
    </saml:Assertion>
</samlp:Response>"""
    return xml


class SAMLXMLValidatorTest(TestCase):
    """Tests for XML validation."""

    def test_valid_response(self):
        xml = build_saml_response()
        validator = SAMLXMLValidator(xml)
        validator.parse()
        self.assertTrue(validator.validate_structure())

    def test_invalid_xml(self):
        with self.assertRaises(SAMLValidationError):
            validator = SAMLXMLValidator("not xml at all")
            validator.parse()

    def test_xxe_attack_detection(self):
        xml = """<?xml version="1.0"?>
<!DOCTYPE foo [
  <!ENTITY xxe SYSTEM "file:///etc/passwd">
]>
<samlp:Response xmlns:samlp="urn:oasis:names:tc:SAML:2.0:protocol">
</samlp:Response>"""
        with self.assertRaises(SAMLValidationError):
            validator = SAMLXMLValidator(xml)
            validator.parse()

    def test_failed_status(self):
        xml = build_saml_response(status_success=False)
        validator = SAMLXMLValidator(xml)
        validator.parse()
        with self.assertRaises(SAMLValidationError):
            validator.validate_structure()

    def test_expired_assertion(self):
        past = (datetime.now(timezone.utc) - timedelta(hours=2)).strftime(
            '%Y-%m-%dT%H:%M:%SZ'
        )
        xml = build_saml_response(
            not_before=(datetime.now(timezone.utc) - timedelta(hours=3)).strftime(
                '%Y-%m-%dT%H:%M:%SZ'
            ),
            not_on_or_after=past,
        )
        validator = SAMLXMLValidator(xml)
        validator.parse()
        with self.assertRaises(SAMLValidationError):
            validator.validate_structure()

    def test_wrong_version(self):
        xml = build_saml_response().replace('Version="2.0"', 'Version="1.1"', 1)
        validator = SAMLXMLValidator(xml)
        validator.parse()
        with self.assertRaises(SAMLValidationError):
            validator.validate_structure()

    def test_oversized_xml(self):
        # Create XML that exceeds the size limit
        large_xml = "x" * 600000
        with self.assertRaises(SAMLValidationError):
            validator = SAMLXMLValidator(large_xml)
            validator.parse()


class SAMLResponseParserTest(TestCase):
    """Tests for SAML response parsing."""

    def setUp(self):
        self.attribute_mapping = SAML_TEST_SETTINGS['attribute_mapping']

    def test_parse_name_id(self):
        xml = build_saml_response(name_id='testuser@example.com')
        validator = SAMLXMLValidator(xml)
        root = validator.parse()

        parser = SAMLResponseParser(root, self.attribute_mapping)
        parser.parse()

        self.assertEqual(parser.name_id, 'testuser@example.com')

    def test_parse_attributes(self):
        xml = build_saml_response(
            first_name='Jane',
            last_name='Smith',
            email='jane@example.com',
        )
        validator = SAMLXMLValidator(xml)
        root = validator.parse()

        parser = SAMLResponseParser(root, self.attribute_mapping)
        parser.parse()

        mapped = parser.get_mapped_attributes()
        self.assertEqual(mapped['first_name'], 'Jane')
        self.assertEqual(mapped['last_name'], 'Smith')
        self.assertEqual(mapped['email'], 'jane@example.com')

    def test_parse_session_index(self):
        xml = build_saml_response()
        validator = SAMLXMLValidator(xml)
        root = validator.parse()

        parser = SAMLResponseParser(root, self.attribute_mapping)
        parser.parse()

        self.assertEqual(parser.session_index, '_session_789')

    def test_parse_issuer(self):
        xml = build_saml_response(issuer='https://custom-idp.example.com/')
        validator = SAMLXMLValidator(xml)
        root = validator.parse()

        parser = SAMLResponseParser(root, self.attribute_mapping)
        parser.parse()

        self.assertEqual(parser.issuer, 'https://custom-idp.example.com/')

    def test_get_user_identity(self):
        xml = build_saml_response(
            name_id='user@example.com',
            first_name='John',
            last_name='Doe',
            email='user@example.com',
        )
        validator = SAMLXMLValidator(xml)
        root = validator.parse()

        parser = SAMLResponseParser(root, self.attribute_mapping)
        identity = parser.get_user_identity()

        self.assertEqual(identity['name_id'], 'user@example.com')
        self.assertIn('mapped_attributes', identity)
        self.assertEqual(identity['mapped_attributes']['first_name'], 'John')


@override_settings(
    SAML_SP_SETTINGS=SAML_TEST_SETTINGS,
    AUTHENTICATION_BACKENDS=['saml_sp.auth_backend.SAMLAuthenticationBackend'],
)
class SAMLAuthBackendTest(TestCase):
    """Tests for SAML authentication backend."""

    def test_create_new_user(self):
        backend = SAMLAuthenticationBackend()
        user_identity = {
            'name_id': 'newuser@example.com',
            'mapped_attributes': {
                'username': 'newuser@example.com',
                'email': 'newuser@example.com',
                'first_name': 'New',
                'last_name': 'User',
            },
        }

        user = backend.authenticate(saml_user_identity=user_identity)
        self.assertIsNotNone(user)
        self.assertEqual(user.username, 'newuser@example.com')
        self.assertEqual(user.email, 'newuser@example.com')
        self.assertEqual(user.first_name, 'New')
        self.assertEqual(user.last_name, 'User')
        self.assertFalse(user.has_usable_password())

    def test_authenticate_existing_user(self):
        User.objects.create_user(
            username='existing@example.com',
            email='existing@example.com',
            first_name='Old',
            last_name='Name',
        )

        backend = SAMLAuthenticationBackend()
        user_identity = {
            'name_id': 'existing@example.com',
            'mapped_attributes': {
                'username': 'existing@example.com',
                'email': 'existing@example.com',
                'first_name': 'Updated',
                'last_name': 'Name',
            },
        }

        user = backend.authenticate(saml_user_identity=user_identity)
        self.assertIsNotNone(user)
        self.assertEqual(user.first_name, 'Updated')

    def test_none_identity_returns_none(self):
        backend = SAMLAuthenticationBackend()
        user = backend.authenticate(saml_user_identity=None)
        self.assertIsNone(user)

    def test_empty_name_id_returns_none(self):
        backend = SAMLAuthenticationBackend()
        user_identity = {
            'name_id': '',
            'mapped_attributes': {},
        }
        user = backend.authenticate(saml_user_identity=user_identity)
        self.assertIsNone(user)


